const db = window.supabase?.createClient?.(cfg.supabaseUrl, cfg.supabaseKey);
const $ = (id) => document.getElementById(id);
const state = { events: [], feedback: [], appeals: [], roles: [], imports: [], adminAudit: [], cases: [], qualityRounds: [], acceptanceRounds: [], pendingDelete: null, actor: localStorage.getItem('r2v_quality_actor') || '', workstream: localStorage.getItem('r2v_quality_workstream')==='multi'?'multi':'single' };
