function esc(v=''){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}
function pct(n,d){return d ? `${(n/d*100).toFixed(1)}%` : '—';}
function day(v){if(!v)return ''; const d=new Date(v); return Number.isNaN(d.valueOf())?String(v).slice(0,10):d.toISOString().slice(0,10);}
function dateTime(v){if(!v)return '—';const d=new Date(v);if(Number.isNaN(d.valueOf()))return String(v).replace('T',' ').slice(0,16);return new Intl.DateTimeFormat('zh-CN',{timeZone:'Asia/Shanghai',year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hourCycle:'h23'}).format(d).replaceAll('/','-');}
function normalizeName(v=''){const s=String(v).trim(); return s.replace(/^[a-zA-Z][a-zA-Z0-9._-]*(?=[\u4e00-\u9fff])/,'').trim();}
function excelInspectorName(v=''){const s=String(v||'').trim(),names=s.match(/[\u3400-\u9fff·]{2,8}/g);return normalizeName(names?.at(-1)||s.replace(/^[a-zA-Z0-9._@\-\s:：()（）/\\]+/,'').trim());}
function hashText(s){let h=2166136261; for(let i=0;i<s.length;i++){h^=s.charCodeAt(i);h=Math.imul(h,16777619);}return (h>>>0).toString(16).padStart(8,'0');}
function showStatus(text,error=false){const el=$('statusBar');el.textContent=text;el.className=`status-bar${error?' error':''}`;clearTimeout(showStatus.t);showStatus.t=setTimeout(()=>el.classList.add('hidden'),6500);}
function chunk(arr,n=500){const out=[];for(let i=0;i<arr.length;i+=n)out.push(arr.slice(i,i+n));return out;}
function dedupeBy(arr,key){const out=new Map();for(const item of arr){const id=item[key];if(!out.has(id)){out.set(id,item);continue;}const prev=out.get(id),evidence=[...new Set([...(prev.evidence||[]),...(item.evidence||[])])];out.set(id,{...prev,...item,...(prev.evidence||item.evidence?{evidence}:{})});}return [...out.values()];}
function groupBy(arr,keyFn){return arr.reduce((out,item)=>{const key=keyFn(item);(out[key]??=[]).push(item);return out;},{});}
function isInspector(name){const role=state.roles.find(r=>r.person_name===name)?.role;return role==='inspector'||(!role&&inspectorFallback.has(name));}
function workstreamLabel(){return WORKSTREAMS[state.workstream]||WORKSTREAMS.single;}
function importWorkstream(row){return String(row?.file_name||'').startsWith('【多镜头】')?'multi':'single';}
function rowWorkstream(row){if(row?.raw_row?.workstream==='multi')return 'multi';const item=state.imports.find(i=>i.id===row?.import_id);return item?importWorkstream(item):'single';}
function activeEvents(){return state.events.filter(e=>rowWorkstream(e)===state.workstream);}
function activeFeedback(){return state.feedback.filter(f=>rowWorkstream(f)===state.workstream);}
function activeImports(){return state.imports.filter(i=>importWorkstream(i)===state.workstream);}
function periodBounds(){const v=$('periodSelect')?.value||'all',today=day(new Date());if(v==='all')return {start:'',end:'',label:'全部累计'};if(v==='custom'){const start=$('startDate')?.value||'',end=$('endDate')?.value||'';return {start,end,label:start||end?`${start||'最早'} 至 ${end||'最新'}`:'请选择日期'};}const d=new Date(`${today}T00:00:00Z`);d.setUTCDate(d.getUTCDate()-Number(v)+1);return {start:day(d),end:today,label:v==='1'?today:`${day(d)} 至 ${today}`};}
function inPeriod(date){const key=day(date),{start,end}=periodBounds();if(!key)return false;return (!start||key>=start)&&(!end||key<=end);}
function syncPeriodDates(){const select=$('periodSelect'),today=day(new Date()),todayOption=select.querySelector('option[value="1"]');todayOption.textContent=`单日（今天：${today}）`;const v=select.value;if(v==='custom')return;if(v==='all'){$('startDate').value='';$('endDate').value='';return;}const bounds=periodBounds();$('startDate').value=bounds.start;$('endDate').value=bounds.end;}
function setPeriodPreset(){syncPeriodDates();renderAll();}
function useCustomDates(){if($('startDate').value||$('endDate').value)$('periodSelect').value='custom';}
function applyPeriod(){const start=$('startDate').value,end=$('endDate').value;if(start&&end&&start>end)return showStatus('开始日不能晚于结束日。',true);renderAll();showStatus(`已按 ${periodBounds().label} 重新计算。`);}

async function ensureActor(){if(state.actor)return state.actor;const name=prompt('请输入你的姓名。上传、申诉和裁决会记录这个名字。','');if(!name?.trim())return '';state.actor=name.trim();localStorage.setItem('r2v_quality_actor',state.actor);renderIdentity();return state.actor;}
function renderIdentity(){$('identityBtn').textContent=state.actor||'设置姓名';}

async function loadAll(){
  if(!db){showStatus('云端配置未加载，请刷新页面。',true);return;}
  const tables=[['events','r2v_quality_events','event_time','event_key',200000],['feedback','r2v_quality_feedback','updated_at','feedback_key',100000],['appeals','r2v_quality_appeals','updated_at','id',50000],['roles','r2v_quality_staff_roles','person_name','person_name',10000],['imports','r2v_quality_imports','created_at','id',10000],['adminAudit','r2v_quality_admin_audit','created_at','id',10000]];
  try{
    showStatus('正在读取全部历史流水…');
    for(const [key,table,order,tie,max] of tables){const rows=[];for(let from=0;from<max;from+=1000){let query=db.from(table).select('*').order(order,{ascending:key==='roles'});if(tie!==order)query=query.order(tie,{ascending:true});const {data,error}=await query.range(from,Math.min(from+999,max-1));if(error)throw error;rows.push(...(data||[]));if(!data||data.length<1000)break;}state[key]=rows;}
    rebuild();renderAll();
  }catch(e){showStatus(`数据库尚未就绪：${e.message}。请先执行 supabase-schema.sql。`,true);}
}

function sortedEvents(tid){return activeEvents().filter(e=>e.tid===tid).sort((a,b)=>new Date(a.event_time)-new Date(b.event_time));}
function lastBefore(events,index,predicate){for(let i=index-1;i>=0;i--)if(predicate(events[i]))return events[i];return null;}
function isAnnotationEvent(e){return ['标注','标注派单'].includes(e?.event_name);}
function originalAnnotator(events,index){const cutoff=new Date(events[index]?.event_time).valueOf(),ordered=events.filter(e=>isAnnotationEvent(e)&&e.operator_name&&new Date(e.event_time).valueOf()<=cutoff).sort((a,b)=>new Date(a.event_time)-new Date(b.event_time)),completed=ordered.filter(e=>e.event_name==='标注').at(-1),firstAssignment=ordered.find(e=>e.event_name==='标注派单'),chosen=completed||firstAssignment;return chosen?normalizeName(chosen.operator_name):'待匹配';}
function annotationOwnerByDate(events,feedbackDate){const cutoff=day(feedbackDate),ordered=events.filter(e=>isAnnotationEvent(e)&&e.operator_name&&(!cutoff||day(e.event_time)<=cutoff)).sort((a,b)=>new Date(a.event_time)-new Date(b.event_time)),completed=ordered.filter(e=>e.event_name==='标注').at(-1),firstAssignment=ordered.find(e=>e.event_name==='标注派单'),chosen=completed||firstAssignment;return chosen?normalizeName(chosen.operator_name):'';}

function buildQualityRounds(){
  const groups=groupBy(activeEvents().filter(e=>e.channel==='quality'),e=>e.tid);const rounds=[];
  for(const [tid,events0] of Object.entries(groups)){const events=events0.sort((a,b)=>new Date(a.event_time)-new Date(b.event_time));let round=0;
    events.forEach((e,i)=>{if(!['质检通过','质检不通过','质检打回'].includes(e.event_name))return;if(e.event_name==='质检打回'&&lastBefore(events,i,x=>x.event_name==='验收打回')&&!lastBefore(events,i,x=>x.event_name==='标注'&&new Date(x.event_time)>new Date(lastBefore(events,i,y=>y.event_name==='验收打回')?.event_time||0)))return;round++;rounds.push({tid,round,event:e.event_name,date:e.event_time,annotator:originalAnnotator(events,i),inspector:normalizeName(e.operator_name)||'待匹配',reason:e.reject_reason||'',first:round===1,invalid:e.event_name==='质检不通过'});});
  }return rounds;
}

function buildAcceptanceRounds(){
  const groups=groupBy(activeEvents(),e=>e.tid);const rounds=[];
  for(const [tid,events0] of Object.entries(groups)){const events=events0.sort((a,b)=>new Date(a.event_time)-new Date(b.event_time)),entries=events.map((e,i)=>e.event_name==='进入验收池'?i:-1).filter(i=>i>=0),segments=[];
    if(entries.length)entries.forEach((start,ri)=>segments.push({start,end:entries[ri+1]??events.length}));else if(state.workstream==='multi'){let start=-1;events.forEach((e,i)=>{if(e.event_name==='验收派单'&&start<0)start=i;if(start>=0&&['验收通过','验收不通过'].includes(e.event_name)){segments.push({start,end:i+1});start=-1;}});}
    segments.forEach(({start,end},ri)=>{const decisions=[];for(let i=start;i<end;i++)if(['验收通过','验收不通过'].includes(events[i].event_name))decisions.push({e:events[i],i});if(!decisions.length)return;const final=decisions.at(-1);let qc=null;for(let i=final.i-1;i>=0;i--)if(events[i].event_name==='质检通过'&&events[i].operator_name){qc={e:events[i],i};break;}const ai=qc?.i??start;rounds.push({key:`${tid}:${ri+1}`,tid,round:ri+1,entryDate:events[start].event_time,resultDate:final.e.event_time,result:final.e.event_name==='验收通过'?'passed':'failed',reason:final.e.reject_reason||'',inspector:normalizeName(qc?.e.operator_name)||'待匹配',annotator:originalAnnotator(events,ai),events:events.slice(start,end)});});
  }return rounds;
}

function feedbackBusinessKey(f){const detail=String(f.issue_detail||'').trim().replace(/\s+/g,' '),stream=rowWorkstream(f);return detail?`${stream}|${f.source||'quality'}|${f.tid}|${day(f.feedback_date)}|${detail}`:`${stream}|${f.source||'quality'}|${f.tid}|${day(f.feedback_date)}|row:${f.raw_row?.excelRow||f.feedback_key}`;}
function activeFeedbackRows(){const importTime=new Map(state.imports.map(i=>[i.id,new Date(i.created_at).valueOf()||0])),onlineKeys=['manualAnnotator','manualInspector','manualMatchUpdatedBy','manualMatchUpdatedAt','reviewCategory','trackingUpdatedBy','trackingUpdatedAt','changedManagedOnline'],rows=activeFeedback().sort((a,b)=>(importTime.get(b.import_id)||new Date(b.updated_at).valueOf()||0)-(importTime.get(a.import_id)||new Date(a.updated_at).valueOf()||0)),active=new Map();for(const row of rows){const key=feedbackBusinessKey(row),current=active.get(key),trackingAt=row.raw_row?.changedManagedOnline?(new Date(row.raw_row?.trackingUpdatedAt||row.updated_at).valueOf()||0):-1;if(!current){active.set(key,{...row,evidence:[...(row.evidence||[])],_feedbackKeys:[row.feedback_key],_changedTrackingAt:trackingAt});continue}current._feedbackKeys.push(row.feedback_key);current.evidence=[...new Set([...(current.evidence||[]),...(row.evidence||[])])];if(trackingAt>(current._changedTrackingAt??-1)){current.changed=row.changed;current._changedTrackingAt=trackingAt;}const raw={...(current.raw_row||{})};for(const k of onlineKeys)if(raw[k]===undefined&&row.raw_row?.[k]!==undefined)raw[k]=row.raw_row[k];current.raw_row=raw;}return [...active.values()];}
function latestAppeal(feedbackKey,aliases=[]){const keys=new Set([feedbackKey,...aliases]);return state.appeals.filter(a=>keys.has(a.feedback_key)&&a.status!=='withdrawn').sort((a,b)=>new Date(b.updated_at)-new Date(a.updated_at))[0];}
function rebuild(){
  state.qualityRounds=buildQualityRounds();state.acceptanceRounds=buildAcceptanceRounds();const manualByTid=new Map(activeFeedback().filter(f=>f.raw_row?.manualAnnotator||f.raw_row?.manualInspector).map(f=>[f.tid,f.raw_row])),annotationEventsByTid=groupBy(activeEvents().filter(e=>e.channel==='quality'&&isAnnotationEvent(e)&&e.operator_name),e=>e.tid);state.qualityRounds.forEach(r=>{const m=manualByTid.get(r.tid);if(m?.manualAnnotator)r.annotator=m.manualAnnotator;if(m?.manualInspector)r.inspector=m.manualInspector;});state.acceptanceRounds.forEach(r=>{const m=manualByTid.get(r.tid);if(m?.manualAnnotator)r.annotator=m.manualAnnotator;if(m?.manualInspector)r.inspector=m.manualInspector;});const firstByTid=new Map(state.qualityRounds.filter(r=>r.first).map(r=>[r.tid,r]));
  const feedbackCases=activeFeedbackRows().map(f=>{const q=firstByTid.get(f.tid),manual=f.raw_row||{},tidManual=manualByTid.get(f.tid)||{},roundRelevant=q&&(!f.feedback_date||day(q.date)<=day(f.feedback_date)),roundAnnotator=roundRelevant&&q.annotator!=='待匹配'?q.annotator:'',roundInspector=roundRelevant&&q.inspector!=='待匹配'?q.inspector:'',datedAnnotator=annotationOwnerByDate(annotationEventsByTid[f.tid]||[],f.feedback_date);const app=latestAppeal(f.feedback_key,f._feedbackKeys),invalid=roundRelevant&&q?.invalid===true;return {...f,kind:'quality',annotator:manual.manualAnnotator||tidManual.manualAnnotator||roundAnnotator||datedAnnotator||'待匹配',responsible_inspector:manual.manualInspector||tidManual.manualInspector||roundInspector||normalizeName(f.inspector_name)||'待匹配',case_date:roundRelevant?q.date:f.feedback_date,appeal:app,invalid,final_error:!invalid&&['P0','P1'].includes(f.severity)&&app?.status!=='approved'};});
  const known=new Set(feedbackCases.map(c=>c.tid));const synthetic=state.qualityRounds.filter(r=>r.first&&['质检不通过','质检打回'].includes(r.event)&&!known.has(r.tid)).map(r=>({feedback_key:`flow:${r.tid}:${r.round}`,tid:r.tid,feedback_date:day(r.date),source:'quality',severity:'待定级',issue_category:r.invalid?'双方拒绝（无效）':'流水打回',issue_detail:r.reason||(r.invalid?'标注和质检均拒绝，该Case不进入准确率分母':'质检明确打回，缺少线下定级'),inspector_name:r.inspector,evidence:[],kind:'quality',annotator:r.annotator,responsible_inspector:r.inspector,case_date:r.date,invalid:r.invalid,final_error:!r.invalid,appeal:null,synthetic:true}));
  const acceptance=state.acceptanceRounds.filter(r=>r.result==='failed').map(r=>({feedback_key:`acceptance:${r.key}`,tid:r.tid,feedback_date:day(r.resultDate),source:'acceptance',severity:'—',issue_category:'验收不通过',issue_detail:r.reason,inspector_name:r.inspector,evidence:[],kind:'acceptance',annotator:r.annotator,responsible_inspector:r.inspector,case_date:r.entryDate,final_error:true,appeal:null,round:r.round,events:r.events}));
  state.cases=[...feedbackCases,...synthetic,...acceptance];
}

function aggregate(){
  const qRounds=state.qualityRounds.filter(r=>r.first&&!r.invalid&&inPeriod(r.date));const qByTid=new Map(qRounds.map(r=>[r.tid,r]));const qCases=state.cases.filter(c=>c.kind==='quality'&&!c.invalid&&qByTid.has(c.tid));const aRounds=state.acceptanceRounds.filter(r=>inPeriod(r.entryDate));
  const people=new Map();const get=n=>{if(!people.has(n))people.set(n,{name:n,qTotal:0,p0:0,p1:0,p2:0,errors:new Set(),approved:0,aTotal:0,aFail:0});return people.get(n)};
  qRounds.forEach(r=>get(r.annotator).qTotal++);qCases.forEach(c=>{const p=get(c.annotator);if(c.severity==='P0')p.p0++;if(c.severity==='P1')p.p1++;if(c.severity==='P2')p.p2++;if(c.appeal?.status==='approved')p.approved++;if(c.final_error)p.errors.add(c.tid);});aRounds.forEach(r=>{const p=get(r.annotator);p.aTotal++;if(r.result==='failed')p.aFail++;});
  const inspectors=new Map();aRounds.forEach(r=>{const p=inspectors.get(r.inspector)||{name:r.inspector,total:0,fail:0};p.total++;if(r.result==='failed')p.fail++;inspectors.set(r.inspector,p)});
  return {qRounds,qCases,aRounds,people:[...people.values()].filter(p=>p.name!=='待匹配').sort((a,b)=>b.qTotal-a.qTotal),inspectors:[...inspectors.values()].filter(p=>p.name!=='待匹配').sort((a,b)=>b.total-a.total)};
}

function renderAll(){renderIdentity();renderOverview();renderDailyStats();renderDailyPeople();renderPeople();renderCases();renderAppeals();renderImports();}
function renderOverview(){const a=aggregate(),errors=new Set(a.qCases.filter(c=>c.final_error).map(c=>c.tid));$('mQcTotal').textContent=a.qRounds.length;$('mQcErrors').textContent=errors.size;$('mQcAccuracy').textContent=pct(a.qRounds.length-errors.size,a.qRounds.length);$('mAcceptanceTotal').textContent=a.aRounds.length;$('mInspectorAccuracy').textContent=pct(a.aRounds.filter(r=>r.result==='passed').length,a.aRounds.length);
  const toModify=appealFilterBase().filter(c=>c.changed!==true).length,appealing=appealFilterBase().filter(c=>c.appeal?.status==='submitted').length,ungraded=a.qCases.filter(c=>c.severity==='待定级').length,match=caseFilterBase().filter(c=>c.annotator==='待匹配'||c.responsible_inspector==='待匹配').length;
  $('todoList').innerHTML=[['标注待修改',toModify,'申诉中心待修改/提交','appeals'],['申诉待裁决',appealing,'裁决后自动回算','appeals'],['历史待定级',ungraded,'不影响P级分布','cases'],['人员待匹配',match,'需要补角色或流水','cases']].map(x=>`<div class="todo-row"><span class="todo-count">${x[1]}</span><div><strong>${x[0]}</strong><small>${x[2]}</small></div><button class="text-button" data-go="${x[3]}">处理</button></div>`).join('');
  const sev=['P0','P1','P2'],counts=sev.map(s=>a.qCases.filter(c=>c.severity===s).length),max=Math.max(1,...counts);$('severityBars').innerHTML=sev.map((s,i)=>`<div class="bar-row"><strong>${s}</strong><div class="bar-track"><div class="bar-fill ${s.toLowerCase()}" style="width:${counts[i]/max*100}%"></div></div><span>${counts[i]}</span></div>`).join('');renderReviewDashboard();$('overviewPeople').innerHTML=peopleRows(a.people.slice(0,8),false);bindGo();}
function renderReviewDashboard(){const rows=caseFilterBase(),order=['未选择','同 ID 判定错误','ID 漏标','参考图数量不足','景别错误','机位高度错误','主体朝向错误','光影错误','时段错误','造型是否一致错误','有疑问'],colors=['oklch(82% .015 240)','oklch(66% .13 305)','oklch(65% .16 20)','oklch(72% .15 75)','oklch(62% .14 245)','oklch(66% .12 215)','oklch(64% .12 175)','oklch(75% .15 95)','oklch(63% .13 275)','oklch(67% .14 345)','oklch(68% .14 55)'],counts=new Map();rows.forEach(c=>{const key=reviewCategory(c)||'未选择';counts.set(key,(counts.get(key)||0)+1)});const labels=[...order.filter(x=>counts.has(x)),...[...counts.keys()].filter(x=>!order.includes(x)).sort((a,b)=>a.localeCompare(b,'zh-CN'))],total=rows.length;let cursor=0;const segments=labels.map((label,i)=>{const value=counts.get(label)||0,start=total?cursor/total*100:0;cursor+=value;const end=total?cursor/total*100:0;return `${colors[i%colors.length]} ${start}% ${end}%`});$('reviewCaseTotal').textContent=`${total} 条`;$('reviewPieTotal').textContent=total;$('reviewPie').style.background=total?`conic-gradient(${segments.join(',')})`:'oklch(92% .01 240)';$('reviewPie').setAttribute('aria-label',total?`错误Case复盘分布，共${total}条`:'当前日期范围暂无Case');$('reviewLegend').innerHTML=labels.length?labels.map((label,i)=>`<div class="review-legend-row"><span class="review-swatch" style="background:${colors[i%colors.length]}"></span><span>${esc(label)}</span><strong>${counts.get(label)||0}</strong></div>`).join(''):'<p class="empty-review">当前日期范围暂无Case。</p>';}
