function filteredAppeals(){const value=id=>$(id)?.value||'all',text=id=>($(id)?.value||'').trim().toLowerCase(),tid=text('appealTidFilter'),issue=text('appealIssueFilter'),reason=text('appealReasonFilter'),decision=text('appealDecisionFilter');let rows=appealFilterBase();const exact=[[value('appealDateFilter'),c=>appealCaseDate(c)],[value('appealAnnotatorFilter'),c=>c.annotator],[value('appealInspectorFilter'),c=>c.responsible_inspector],[value('appealSeverityFilter'),c=>c.severity],[value('appealReturnedFilter'),c=>qualityReturned(c)],[value('appealAccuracyFilter'),c=>accuracyLinkStatus(c)],[value('appealSubmitterFilter'),c=>c.appeal?.submitted_by||'—'],[value('appealStatusFilter'),c=>appealDisplayStatus(c)],[value('appealDeciderFilter'),c=>c.appeal?.decided_by||'—'],[value('appealUpdatedFilter'),c=>c.appeal?day(c.appeal.updated_at):'—'],[value('appealChangedFilter'),c=>changedStatus(c)],[value('appealReviewFilter'),c=>reviewCategory(c)||'未选择']];for(const [selected,getter] of exact)if(selected!=='all')rows=rows.filter(c=>getter(c)===selected);if(tid)rows=rows.filter(c=>String(c.tid||'').toLowerCase().includes(tid));if(issue)rows=rows.filter(c=>String(c.issue_detail||'').toLowerCase().includes(issue));if(reason)rows=rows.filter(c=>String(c.appeal?.reason||'').toLowerCase().includes(reason));if(decision)rows=rows.filter(c=>String(c.appeal?.decision_note||'').toLowerCase().includes(decision));return rows.sort(feedbackOrder);}
