function openCase(key){const c=state.cases.find(x=>x.feedback_key===key);if(!c)return;const events=sortedEvents(c.tid);const evidence=Array.isArray(c.evidence)?c.evidence:[];let action='';if(c.kind==='quality'&&!c.invalid&&['P0','P1'].includes(c.severity)){action=`<section class="drawer-section appeal-decision-section"><h3>申诉处理</h3>${c.appeal?`<div class="appeal-summary">${appealStatusBadge(c)}<p>${esc(c.appeal.reason)}</p></div>${c.appeal.status==='submitted'?`<form id="decisionForm" class="appeal-form"><label for="decisionNote">质检裁决意见 <span>判定失败时必填</span></label><textarea id="decisionNote" name="decisionNote" placeholder="说明同意或驳回申诉的规则依据、判定理由"></textarea><div class="appeal-actions"><button class="button small decision-success" type="button" data-decision="approved">判定成功</button><button class="button small decision-failure" type="button" data-decision="rejected">判定失败</button></div><p id="decisionError" class="field-error hidden">判定失败必须填写质检裁决意见。</p></form>`:`<div class="decision-readonly"><span>质检裁决意见</span><p>${esc(c.appeal.decision_note||'未填写')}</p></div>`}`:`<form id="appealForm" class="appeal-form"><textarea name="reason" required placeholder="填写申诉理由与规则依据"></textarea><button class="button primary" type="submit">提交共享申诉</button></form>`}</section>`;}
  const appealTrail=c.appeal?`<section class="drawer-section"><h3>申诉流水</h3><div class="timeline"><div class="timeline-row"><time>${esc(dateTime(c.appeal.created_at))}</time><strong>提交申诉</strong><span>${esc(c.appeal.submitted_by)}：${esc(c.appeal.reason)}</span></div>${c.appeal.status!=='submitted'?`<div class="timeline-row"><time>${esc(dateTime(c.appeal.updated_at))}</time><strong>${appealStatus(c.appeal.status)}</strong><span>${esc(c.appeal.decided_by||'未记录裁决人')}：${esc(c.appeal.decision_note||'未填写裁决说明')}</span></div>`:''}</div></section>`:'';
  $('drawerContent').innerHTML=`<p class="eyebrow">${c.kind==='quality'?'QUALITY CASE':'ACCEPTANCE CASE'}</p><h2>${esc(c.tid)}</h2><section class="drawer-section"><div class="detail-grid"><div><span>标注责任人</span>${esc(c.annotator)}</div><div><span>质检责任人</span>${esc(c.responsible_inspector)}</div><div><span>反馈日期</span>${esc(day(c.feedback_date))}</div><div><span>错误等级</span>${c.kind==='quality'?severityBadge(c.severity):'验收不通过'}</div><div><span>问题类别</span>${esc(c.issue_category||'—')}</div><div><span>最终计错</span>${c.final_error?'是':'否'}</div></div></section><section class="drawer-section"><h3>反馈意见</h3><p>${esc(c.issue_detail||'暂无')}</p></section>${evidence.length?`<section class="drawer-section"><h3>质检截图</h3><div class="evidence-grid">${evidence.map(u=>`<a href="${esc(u)}" target="_blank" rel="noreferrer"><img src="${esc(u)}" alt="质检证据"></a>`).join('')}</div></section>`:''}${action}${appealTrail}<section class="drawer-section"><h3>完整流水</h3><div class="timeline">${events.map(e=>`<div class="timeline-row"><time>${esc(dateTime(e.event_time))}</time><strong>${esc(e.event_name)}</strong><span>${esc(normalizeName(e.operator_name)||e.reject_reason||'')}</span></div>`).join('')||'暂无匹配流水'}</div></section>`;
  $('caseDrawer').classList.add('open');$('caseDrawer').setAttribute('aria-hidden','false');$('drawerBackdrop').classList.remove('hidden');const form=$('appealForm');if(form)form.onsubmit=async e=>{e.preventDefault();await submitAppeal(c,form.reason.value)};document.querySelectorAll('[data-decision]').forEach(b=>b.onclick=()=>decideAppeal(c,b.dataset.decision,$('decisionNote')?.value||''));}
function closeDrawer(){$('caseDrawer').classList.remove('open');$('caseDrawer').setAttribute('aria-hidden','true');$('drawerBackdrop').classList.add('hidden');}
async function submitAppeal(c,reason){const actor=await ensureActor();if(!actor)return;reason=String(reason||'').trim();if(!reason)return showStatus('请填写申诉理由。',true);const form=$('appealForm'),button=form?.querySelector('button[type="submit"]');if(button){button.disabled=true;button.textContent='正在保存到共享看板…';}const {data,error}=await db.from('r2v_quality_appeals').insert({feedback_key:c.feedback_key,tid:c.tid,reason,status:'submitted',submitted_by:actor}).select('id,feedback_key,tid,reason,status,submitted_by,created_at,updated_at').single();if(error||!data?.id){if(button){button.disabled=false;button.textContent='提交共享申诉';}showStatus(`申诉未保存：${error?.message||'云端未返回保存结果'}，填写内容已保留，请重试。`,true);return;}state.appeals.push(data);rebuild();closeDrawer();renderAll();showStatus(`申诉已共享保存（${data.tid}），其他人的看板将自动同步。`);}
async function decideAppeal(c,status,note=''){const actor=await ensureActor();if(!actor||!c.appeal)return;note=String(note||'').trim();const errorEl=$('decisionError'),noteEl=$('decisionNote');if(status==='rejected'&&!note){errorEl?.classList.remove('hidden');noteEl?.focus();return}errorEl?.classList.add('hidden');document.querySelectorAll('[data-decision]').forEach(b=>b.disabled=true);const {data,error}=await db.from('r2v_quality_appeals').update({status,decided_by:actor,decision_note:note}).eq('id',c.appeal.id).select('id,status,decision_note');if(error||!data?.length){document.querySelectorAll('[data-decision]').forEach(b=>b.disabled=false);return showStatus(error?.message||'裁决未写入共享数据库。',true)}closeDrawer();await loadAll();showStatus(status==='approved'?'申诉成功，相关准确率已自动重新计算。':'申诉失败，质检裁决意见已保存，错误继续计入准确率。');}

function renderImports(){const imports=activeImports();$('importHistory').innerHTML=imports.length?imports.slice(0,30).map(i=>`<div class="history-row"><div><strong>${esc(String(i.file_name).replace(/^【多镜头】/,''))}</strong><small> · ${esc(i.file_type)}</small></div><span>${i.row_count} 行</span><span>${esc(i.actor)} · ${esc(dateTime(i.created_at))}</span><button class="text-button import-delete" data-id="${esc(i.id)}">管理员删除</button></div>`).join(''):`<p class="empty-cell">暂无${workstreamLabel()}共享上传记录。</p>`;$('adminAudit').innerHTML=state.adminAudit.length?state.adminAudit.slice(0,20).map(a=>`<div class="history-row"><div><strong>${a.action==='delete_import'?'删除上传记录':'修改管理员密码'}</strong><small>${esc(a.file_name||'')}</small></div><span>${esc(a.actor)}</span><span>${esc(dateTime(a.created_at))}</span></div>`).join(''):'<p class="empty-cell">暂无管理员操作记录。</p>';document.querySelectorAll('.import-delete').forEach(b=>b.onclick=()=>beginDelete(b.dataset.id));}
function beginDelete(id){const item=state.imports.find(i=>i.id===id);if(!item)return;state.pendingDelete=item;$('adminPanel').classList.remove('hidden');$('deleteConfirm').classList.remove('hidden');$('deleteFileName').textContent=`准备删除：${item.file_name}`;$('deletePin').value='';$('deletePin').focus();}
function cancelDelete(){state.pendingDelete=null;$('deleteConfirm').classList.add('hidden');$('deletePin').value='';}
async function deleteImport(){const item=state.pendingDelete,pin=$('deletePin').value,actor=await ensureActor();if(!item||!actor)return;if(!pin)return showStatus('请输入管理员密码。',true);$('confirmDelete').disabled=true;const {data,error}=await db.rpc('r2v_admin_delete_import',{p_import_id:item.id,p_pin:pin,p_actor:actor});$('confirmDelete').disabled=false;if(error)return showStatus(error.message,true);cancelDelete();await loadAll();showStatus(`已删除 ${data.file_name}，移除流水 ${data.events} 条、反馈 ${data.feedback} 条，准确率已重新计算。`);}
async function changeAdminPin(e){e.preventDefault();const form=e.currentTarget,actor=await ensureActor();if(!actor)return;const oldPin=form.oldPin.value,newPin=form.newPin.value;if(!/^\d{4,12}$/.test(newPin))return showStatus('新密码必须为4至12位数字。',true);const submit=form.querySelector('button[type="submit"]');submit.disabled=true;const {error}=await db.rpc('r2v_admin_change_pin',{p_old_pin:oldPin,p_new_pin:newPin,p_actor:actor});submit.disabled=false;if(error)return showStatus(error.message,true);form.reset();await loadAll();showStatus('管理员密码已修改，下次删除请使用新密码。');}
async function readCsv(file){const text=await file.text();const rows=parseCsv(text);if(rows.length<2)throw new Error('CSV没有有效数据');const h=rows[0],idx=n=>h.indexOf(n);return rows.slice(1).filter(r=>r.some(Boolean)).map(r=>({tid:r[idx('TID')]||'',queue_id:r[idx('队列ID')]||'',queue_name:r[idx('队列名称')]||'',catalog_id:r[idx('目录ID')]||'',catalog_name:r[idx('目录名称')]||'',event_time:(r[idx('事件时间')]||'').replace(' ','T')+'+08:00',event_name:r[idx('事件')]||'',operator_uin:r[idx('操作人UIN')]||'',operator_name:r[idx('操作人姓名')]||'',reject_reason:r[idx('不通过原因')]||''}));}
function parseCsv(text){const rows=[];let row=[],cell='',q=false;for(let i=0;i<text.length;i++){const c=text[i],n=text[i+1];if(q&&c==='"'&&n==='"'){cell+='"';i++;}else if(c==='"')q=!q;else if(!q&&c===','){row.push(cell);cell='';}else if(!q&&(c==='\n'||c==='\r')){if(c==='\r'&&n==='\n')i++;row.push(cell);rows.push(row);row=[];cell='';}else cell+=c;}if(cell||row.length){row.push(cell);rows.push(row)}if(rows[0]?.[0]?.charCodeAt(0)===0xfeff)rows[0][0]=rows[0][0].slice(1);return rows;}
function excelDate(v){if(v==null||v==='')return null;if(typeof v==='number'&&v>30000){const d=XLSX.SSF.parse_date_code(v);return `${d.y}-${String(d.m).padStart(2,'0')}-${String(d.d).padStart(2,'0')}`;}const s=String(v).trim().replace(/[年/.]/g,'-').replace(/月/g,'-').replace(/日/g,'');const parts=s.split('-').filter(Boolean);if(parts.length===2)return `${new Date().getFullYear()}-${parts[0].padStart(2,'0')}-${parts[1].padStart(2,'0')}`;return s.slice(0,10);}
async function readFeedback(file){const data=await file.arrayBuffer(),wb=XLSX.read(data,{type:'array',cellDates:false}),ws=wb.Sheets[wb.SheetNames[0]],arr=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});const h=arr[0].map(String),find=(...names)=>{for(const n of names){const i=h.findIndex(x=>x.trim()===n);if(i>=0)return i}return -1},idx={source:find('来源'),date:find('质检日期','反馈日期'),change:find('标注是否需要修改','质检是否打回'),movie:find('影片名'),tid:find('case id','Case ID','TID'),cat:find('问题类别'),detail:find('问题点','问题说明'),inspector:find('质检人'),changed:find('标注是否修改'),reply:11,recheck:find('是否建包质检'),severity:find('错误等级','等级','P级','P级别')};if(idx.change<0)idx.change=2;if(idx.tid<0)throw new Error('质检表未找到 case id 列');const rows=arr.slice(1).map((r,ri)=>{const tid=String(r[idx.tid]||'').trim();if(!tid)return null;const severity=String(r[idx.severity]||'').trim().toUpperCase().replace(/Ｐ/g,'P').replace(/０/g,'0').replace(/１/g,'1').replace(/２/g,'2').replace(/\s+/g,'')||'待定级',detail=String(r[idx.detail]||'').trim(),inspector=excelInspectorName(r[idx.inspector]||r[13]),changeText=String(r[idx.change]||'').trim();const key=hashText([tid,excelDate(r[idx.date]),r[idx.cat],detail,inspector].join('|'));return {feedback_key:key,tid,feedback_date:excelDate(r[idx.date]),source:String(r[idx.source]||'').includes('验收')?'acceptance':'quality',severity:['P0','P1','P2','非人员责任'].includes(severity)?severity:'待定级',issue_category:String(r[idx.cat]||''),issue_detail:detail,inspector_name:inspector,movie_name:String(r[idx.movie]||''),needs_change:changeText==='是'?true:changeText==='否'?false:null,changed:String(r[idx.changed]||'')==='是',annotator_reply:String(r[idx.reply]||''),needs_recheck:String(r[idx.recheck]||'')==='是',evidence:[],raw_row:{excelRow:ri+2}}}).filter(Boolean);return {rows,data};}
async function extractAndUploadImages(data,rows){let zip;try{zip=await JSZip.loadAsync(data)}catch{return}const drawingNames=Object.keys(zip.files).filter(n=>/^xl\/drawings\/drawing\d+\.xml$/.test(n));for(const drawingName of drawingNames){const relName=drawingName.replace('xl/drawings/','xl/drawings/_rels/')+'.rels',relFile=zip.file(relName);if(!relFile)continue;const [drawingXml,relXml]=await Promise.all([zip.file(drawingName).async('text'),relFile.async('text')]),relDoc=new DOMParser().parseFromString(relXml,'text/xml'),relMap={};relDoc.querySelectorAll('Relationship').forEach(x=>relMap[x.getAttribute('Id')]=x.getAttribute('Target'));const doc=new DOMParser().parseFromString(drawingXml,'text/xml');for(const anchor of doc.querySelectorAll('twoCellAnchor,oneCellAnchor')){const rowNode=anchor.querySelector('from row'),blip=anchor.querySelector('blip');if(!rowNode||!blip)continue;const excelRow=Number(rowNode.textContent)+1,rid=blip.getAttribute('r:embed')||blip.getAttributeNS('http://schemas.openxmlformats.org/officeDocument/2006/relationships','embed'),target=relMap[rid];if(!target)continue;const mediaPath='xl/'+target.replace(/^\.\.\//,'').replace(/\\/g,'/'),media=zip.file(mediaPath);if(!media)continue;const row=rows.find(x=>x.raw_row.excelRow===excelRow);if(!row)continue;const blob=await media.async('blob');if(blob.size>20*1024*1024)continue;const ext=mediaPath.split('.').pop().toLowerCase(),mime=ext==='jpg'||ext==='jpeg'?'image/jpeg':`image/${ext}`,path=`feedback/${row.feedback_key}-${hashText(mediaPath)}.${ext}`;const {error}=await db.storage.from('r2v-quality-evidence').upload(path,new Blob([blob],{type:mime}),{upsert:true,contentType:mime});if(!error){const {data:url}=db.storage.from('r2v-quality-evidence').getPublicUrl(path);row.evidence.push(url.publicUrl);}}}}
async function createImport(file,type,count){const actor=await ensureActor();if(!actor)throw new Error('需要设置操作人姓名');const scope=state.workstream==='multi'?'multi|':'',fp=hashText(`${scope}${file.name}|${file.size}|${file.lastModified}`),storedName=state.workstream==='multi'?`【多镜头】${file.name}`:file.name;const query=()=>db.from('r2v_quality_imports').select('id').eq('file_type',type).eq('file_fingerprint',fp).maybeSingle();const {data:existing,error:lookupError}=await query();if(lookupError)throw lookupError;if(existing?.id)return existing.id;const {data,error}=await db.from('r2v_quality_imports').insert({file_name:storedName,file_type:type,file_fingerprint:fp,row_count:count,actor}).select('id').single();if(!error)return data.id;if(error.code==='23505'){const {data:duplicate,error:duplicateError}=await query();if(duplicateError)throw duplicateError;if(duplicate?.id)return duplicate.id;}throw error;}
async function saveEvents(file,type,channel){const rows=await readCsv(file),importId=await createImport(file,type,rows.length),scope=state.workstream==='multi'?'multi':'';const payload=dedupeBy(rows.map(r=>({...r,channel,import_id:importId,event_key:hashText([scope,r.tid,r.event_time,r.event_name,r.operator_uin,r.queue_id].join('|'))})),'event_key');for(const part of chunk(payload,500)){const {error}=await db.from('r2v_quality_events').upsert(part,{onConflict:'event_key'});if(error)throw error;}return payload.length;}
async function fillMissingFeedbackDates(rows){const missing=rows.filter(r=>!r.feedback_date);if(!missing.length)return 0;const {data:imports,error:importError}=await db.from('r2v_quality_imports').select('id,file_name');if(importError)throw importError;const allowed=new Set((imports||[]).filter(i=>importWorkstream(i)===state.workstream).map(i=>i.id)),latestByTid=new Map(),tids=[...new Set(missing.map(r=>r.tid).filter(Boolean))],seenDates=[];for(const part of chunk(tids,200)){const {data,error}=await db.from('r2v_quality_events').select('tid,event_time,import_id').eq('channel','quality').in('tid',part).order('event_time',{ascending:false});if(error)throw error;for(const e of data||[]){if(e.import_id&&!allowed.has(e.import_id))continue;if(!e.import_id&&state.workstream!=='single')continue;const d=day(e.event_time);if(d)seenDates.push(d);if(!latestByTid.has(e.tid)&&d)latestByTid.set(e.tid,d);}}const fallback=seenDates.sort().at(-1)||'';let filled=0;for(const r of missing){const inferred=latestByTid.get(r.tid)||fallback;if(!inferred)continue;r.feedback_date=inferred;r.feedback_key=hashText([state.workstream==='multi'?'multi':'',r.tid,r.feedback_date,r.issue_category,r.issue_detail,r.inspector_name].join('|'));filled++;}return filled;}
async function preserveOnlineFeedbackTracking(payload){const exact=new Map(),business=new Map(),logical=new Map(),tids=[...new Set(payload.map(r=>r.tid).filter(Boolean))];for(const part of chunk(tids,150)){const {data,error}=await db.from('r2v_quality_feedback').select('feedback_key,tid,feedback_date,source,issue_detail,changed,raw_row,updated_at,import_id').in('tid',part).order('updated_at',{ascending:false});if(error)throw error;for(const old of data||[]){if(rowWorkstream(old)!==state.workstream)continue;exact.set(old.feedback_key,old);const businessKey=feedbackBusinessKey(old);if(!business.has(businessKey))business.set(businessKey,old);const rowNo=Number(old.raw_row?.excelRow);if(Number.isFinite(rowNo)){const key=`${state.workstream}|${old.tid}|${day(old.feedback_date)}|${rowNo}`;if(!logical.has(key))logical.set(key,old);}}}for(const row of payload){const rowNo=Number(row.raw_row?.excelRow),old=exact.get(row.feedback_key)||business.get(feedbackBusinessKey(row))||logical.get(`${state.workstream}|${row.tid}|${day(row.feedback_date)}|${rowNo}`),raw=old?.raw_row||{};if(old)row.feedback_key=old.feedback_key;const online={};['manualAnnotator','manualInspector','manualMatchUpdatedBy','manualMatchUpdatedAt','reviewCategory','trackingUpdatedBy','trackingUpdatedAt','changedManagedOnline'].forEach(k=>{if(raw[k]!==undefined)online[k]=raw[k]});if(raw.changedManagedOnline)row.changed=old.changed;row.raw_row={...(row.raw_row||{}),...online};}return payload;}
async function saveFeedback(file){const parsed=await readFeedback(file),rows=parsed.rows.map(r=>{if(state.workstream==='multi'){r.raw_row={...(r.raw_row||{}),workstream:'multi'};r.feedback_key=hashText(['multi',r.tid,r.feedback_date,r.issue_category,r.issue_detail,r.inspector_name].join('|'));}return r}),filled=await fillMissingFeedbackDates(rows),importId=await createImport(file,'feedback',rows.length);showStatus(`正在提取 ${workstreamLabel()} ${file.name} 中的质检截图…${filled?` 已按流水自动补齐 ${filled} 条日期。`:''}`);await extractAndUploadImages(parsed.data,rows);const payload=dedupeBy(await preserveOnlineFeedbackTracking(rows.map(r=>({...r,import_id:importId}))),'feedback_key');for(const part of chunk(payload,300)){const {error}=await db.from('r2v_quality_feedback').upsert(part,{onConflict:'feedback_key'});if(error)throw error;}return payload.length;}
async function importSelected(){const files=[['qualityFlowInput','quality_flow','quality'],['feedbackInput','feedback',''],['acceptanceFlowInput','acceptance_flow','acceptance']].map(x=>[$(x[0]).files[0],x[1],x[2]]).filter(x=>x[0]);if(!files.length)return showStatus('请至少选择一个文件。',true);$('importBtn').disabled=true;$('importBtn').textContent='正在解析并共享保存…';try{let total=0;for(const [file,type,channel] of files)total+=type==='feedback'?await saveFeedback(file):await saveEvents(file,type,channel);showStatus(`上传完成，共处理 ${total} 行。重复数据已自动更新，不会重复累计。`);await loadAll();}catch(e){showStatus(`上传失败：${e.message}`,true);}finally{$('importBtn').disabled=false;$('importBtn').textContent='解析并保存到共享看板';}}

const VIEW_LABELS={overview:'总览',people:'人员质量',cases:'Case 明细',appeals:'申诉中心',imports:'数据上传'};
function enhanceWorkstreamNavigation(){const nav=$('nav'),views=Object.keys(VIEW_LABELS);nav.innerHTML=Object.entries(WORKSTREAMS).map(([stream,label])=>`<section class="nav-workstream"><div class="nav-workstream-label"><span class="stream-dot ${stream}"></span>${label}</div>${views.map(view=>`<button class="nav-item" data-view="${view}" data-workstream="${stream}">${VIEW_LABELS[view]}</button>`).join('')}</section>`).join('');nav.addEventListener('click',event=>{const button=event.target.closest('.nav-item');if(!button)return;event.preventDefault();event.stopImmediatePropagation();setView(button.dataset.view,button.dataset.workstream)},true);const intro=document.querySelector('.import-intro');if(intro&&!$('uploadWorkstreamBadge'))intro.insertAdjacentHTML('afterbegin','<span id="uploadWorkstreamBadge" class="workstream-badge"></span>');}
function clearWorkstreamSelections(){document.querySelectorAll('.upload-box input').forEach(input=>{input.value='';input.closest('.upload-box')?.classList.remove('selected')});if($('selectedFiles'))$('selectedFiles').textContent='尚未选择文件';['caseDateFilter','caseSourceFilter','caseAnnotatorFilter','caseInspectorFilter','caseSeverityFilter','caseReturnedFilter','caseCategoryFilter','caseReviewFilter','caseStatusFilter','appealDateFilter','appealAnnotatorFilter','appealInspectorFilter','appealSeverityFilter','appealReturnedFilter','appealAccuracyFilter','appealSubmitterFilter','appealStatusFilter','appealDeciderFilter','appealUpdatedFilter','appealChangedFilter','appealReviewFilter'].forEach(id=>{if($(id))$(id).value='all'});['caseSearch','caseTidFilter','caseDetailFilter','appealTidFilter','appealIssueFilter','appealReasonFilter','appealDecisionFilter'].forEach(id=>{if($(id))$(id).value=''});}
function updateWorkstreamChrome(view){const label=workstreamLabel();$('pageTitle').textContent=`${label}${VIEW_LABELS[view]}`;document.querySelectorAll('.nav-item').forEach(n=>n.classList.toggle('active',n.dataset.view===view&&n.dataset.workstream===state.workstream));document.querySelectorAll('.nav-workstream').forEach(group=>group.classList.toggle('current',!!group.querySelector(`[data-workstream="${state.workstream}"]`)));if($('uploadWorkstreamBadge'))$('uploadWorkstreamBadge').textContent=`当前上传到：${label}`;if($('importBtn'))$('importBtn').textContent=`解析并保存到${label}看板`;}
function setView(view,workstream=state.workstream){const changed=workstream!==state.workstream;if(changed){state.workstream=workstream;localStorage.setItem('r2v_quality_workstream',workstream);clearWorkstreamSelections();rebuild();renderAll();}document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));$(`${view}View`).classList.add('active');updateWorkstreamChrome(view);if(view==='cases')renderCases();if(view==='appeals')renderAppeals();}
function bindGo(){document.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>setView(b.dataset.go));}
