async function compressEvidenceBlob(blob){try{const bitmap=await createImageBitmap(blob),maxSide=1280,scale=Math.min(1,maxSide/Math.max(bitmap.width,bitmap.height)),canvas=document.createElement('canvas');canvas.width=Math.max(1,Math.round(bitmap.width*scale));canvas.height=Math.max(1,Math.round(bitmap.height*scale));canvas.getContext('2d',{alpha:false}).drawImage(bitmap,0,0,canvas.width,canvas.height);bitmap.close();const compressed=await new Promise(resolve=>canvas.toBlob(resolve,'image/jpeg',.68));if(compressed)return {blob:compressed,mime:'image/jpeg',ext:'jpg'};}catch{}const type=blob.type||'image/png';return {blob,mime:type,ext:type.includes('jpeg')?'jpg':type.split('/')[1]||'png'};}
extractAndUploadImages=async function(data,rows){let zip;try{zip=await JSZip.loadAsync(data)}catch{return}const drawingNames=Object.keys(zip.files).filter(n=>/^xl\/drawings\/drawing\d+\.xml$/.test(n));for(const drawingName of drawingNames){const relName=drawingName.replace('xl/drawings/','xl/drawings/_rels/')+'.rels',relFile=zip.file(relName);if(!relFile)continue;const [drawingXml,relXml]=await Promise.all([zip.file(drawingName).async('text'),relFile.async('text')]),relDoc=new DOMParser().parseFromString(relXml,'text/xml'),relMap={};relDoc.querySelectorAll('Relationship').forEach(x=>relMap[x.getAttribute('Id')]=x.getAttribute('Target'));const doc=new DOMParser().parseFromString(drawingXml,'text/xml'),drawingDir=drawingName.slice(0,drawingName.lastIndexOf('/'));for(const anchor of doc.querySelectorAll('twoCellAnchor,oneCellAnchor')){const rowNode=anchor.querySelector('from row'),blip=anchor.querySelector('blip');if(!rowNode||!blip)continue;const excelRow=Number(rowNode.textContent)+1,rid=blip.getAttribute('r:embed')||blip.getAttributeNS('http://schemas.openxmlformats.org/officeDocument/2006/relationships','embed'),target=relMap[rid];if(!target)continue;const mediaPath=target.startsWith('/')?target.slice(1):resolveWorkbookPath(drawingDir,target),media=zip.file(mediaPath),row=rows.find(x=>x.raw_row.excelRow===excelRow);if(!media||!row)continue;const original=await media.async('blob');if(original.size>20*1024*1024)continue;const ext=mediaPath.split('.').pop().toLowerCase(),originalMime=ext==='jpg'||ext==='jpeg'?'image/jpeg':`image/${ext}`,compressed=await compressEvidenceBlob(new Blob([original],{type:originalMime})),path=`feedback/${row.feedback_key}-${hashText(mediaPath)}.${compressed.ext}`;const {error}=await db.storage.from('r2v-quality-evidence').upload(path,compressed.blob,{upsert:true,contentType:compressed.mime});if(!error){const {data:url}=db.storage.from('r2v-quality-evidence').getPublicUrl(path);row.evidence.push(url.publicUrl);}}}};
let sharedSyncBusy=false,lastLocalInteractionAt=0;
document.addEventListener('input',()=>{lastLocalInteractionAt=Date.now()});
document.addEventListener('change',()=>{lastLocalInteractionAt=Date.now()});
function sharedSyncPaused(){return document.hidden||$('caseDrawer')?.classList.contains('open')||Date.now()-lastLocalInteractionAt<5000;}
function latestVersion(rows,field){return (rows||[]).reduce((latest,row)=>String(row?.[field]||'')>latest?String(row[field]):latest,'');}
async function syncSharedState(){if(!db||sharedSyncBusy||sharedSyncPaused())return;sharedSyncBusy=true;try{const [feedbackResult,appealResult,importResult]=await Promise.all([db.from('r2v_quality_feedback').select('feedback_key,updated_at').order('updated_at',{ascending:false}).limit(1),db.from('r2v_quality_appeals').select('id,updated_at').order('updated_at',{ascending:false}).limit(1),db.from('r2v_quality_imports').select('id,created_at').order('created_at',{ascending:false}).limit(1)]);if(feedbackResult.error)throw feedbackResult.error;if(appealResult.error)throw appealResult.error;if(importResult.error)throw importResult.error;const remote=[feedbackResult.data?.[0]?.updated_at||'',appealResult.data?.[0]?.updated_at||'',importResult.data?.[0]?.created_at||''],local=[latestVersion(state.feedback,'updated_at'),latestVersion(state.appeals,'updated_at'),latestVersion(state.imports,'created_at')];if(remote.some((version,index)=>version!==local[index]))await loadAll();}catch(error){console.warn('共享状态同步失败',error);}finally{sharedSyncBusy=false;}}
$('refreshBtn').onclick=async()=>{await loadAll();};
setInterval(syncSharedState,12000);
window.addEventListener('focus',()=>setTimeout(syncSharedState,300));
